    /**
     * Get all of PERI_NONSEC's bit fields.
     *
     * (read-write) Detach certain core-local peripherals from Secure SIO, and
     * attach them to Non-secure SIO, so that Non-secure software can use them.
     * Attempting to access one of these peripherals from the Secure SIO when
     * it is attached to the Non-secure SIO, or vice versa, will generate a bus
     * error.
     *
     *                     This register is per-core, and is only present on
     * the Secure SIO.
     *
     *                     Most SIO hardware is duplicated across the Secure
     * and Non-secure SIO, so is not listed in this register.
     */
    inline void get_PERI_NONSEC(bool &INTERP0, bool &INTERP1,
                                bool &TMDS) volatile
    {
        uint32_t curr = PERI_NONSEC;

        INTERP0 = curr & 1u;
        INTERP1 = curr & (1u << 1u);
        TMDS = curr & (1u << 5u);
    }

    /**
     * Set all of PERI_NONSEC's bit fields.
     *
     * (read-write) Detach certain core-local peripherals from Secure SIO, and
     * attach them to Non-secure SIO, so that Non-secure software can use them.
     * Attempting to access one of these peripherals from the Secure SIO when
     * it is attached to the Non-secure SIO, or vice versa, will generate a bus
     * error.
     *
     *                     This register is per-core, and is only present on
     * the Secure SIO.
     *
     *                     Most SIO hardware is duplicated across the Secure
     * and Non-secure SIO, so is not listed in this register.
     */
    inline void set_PERI_NONSEC(bool INTERP0, bool INTERP1, bool TMDS) volatile
    {
        uint32_t curr = PERI_NONSEC;

        curr &= ~(0b1u);
        curr |= (INTERP0 & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (INTERP1 & 0b1u) << 1u;
        curr &= ~(0b1u << 5u);
        curr |= (TMDS & 0b1u) << 5u;

        PERI_NONSEC = curr;
    }

