    /**
     * Get all of RISCV_SOFTIRQ's bit fields.
     *
     * (read-write) Control the assertion of the standard software interrupt
     * (MIP.MSIP) on the RISC-V cores.
     *
     *                     Unlike the RISC-V timer, this interrupt is not
     * routed to a normal system-level interrupt line, so can not be used by
     * the Arm cores.
     *
     *                     It is safe for both cores to write to this register
     * on the same cycle. The set/clear effect is accumulated across both
     * cores, and then applied. If a flag is both set and cleared on the same
     * cycle, only the set takes effect.
     */
    inline void get_RISCV_SOFTIRQ(bool &CORE0_SET, bool &CORE1_SET,
                                  bool &CORE0_CLR, bool &CORE1_CLR) volatile
    {
        uint32_t curr = RISCV_SOFTIRQ;

        CORE0_SET = curr & 1u;
        CORE1_SET = curr & (1u << 1u);
        CORE0_CLR = curr & (1u << 8u);
        CORE1_CLR = curr & (1u << 9u);
    }

    /**
     * Set all of RISCV_SOFTIRQ's bit fields.
     *
     * (read-write) Control the assertion of the standard software interrupt
     * (MIP.MSIP) on the RISC-V cores.
     *
     *                     Unlike the RISC-V timer, this interrupt is not
     * routed to a normal system-level interrupt line, so can not be used by
     * the Arm cores.
     *
     *                     It is safe for both cores to write to this register
     * on the same cycle. The set/clear effect is accumulated across both
     * cores, and then applied. If a flag is both set and cleared on the same
     * cycle, only the set takes effect.
     */
    inline void set_RISCV_SOFTIRQ(bool CORE0_SET, bool CORE1_SET,
                                  bool CORE0_CLR, bool CORE1_CLR) volatile
    {
        uint32_t curr = RISCV_SOFTIRQ;

        curr &= ~(0b1u);
        curr |= (CORE0_SET & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (CORE1_SET & 0b1u) << 1u;
        curr &= ~(0b1u << 8u);
        curr |= (CORE0_CLR & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (CORE1_CLR & 0b1u) << 9u;

        RISCV_SOFTIRQ = curr;
    }

